const Gallery = () => (
  <section className="gallery-section">
    <h2>Hình ảnh cửa hàng</h2>
    <div className="gallery-container">
      <img src="/images/p1.jpg" alt="Bánh dâu tây" className="gallery-item" />
      <img src="/images/p2.jpg" alt="Bánh cầu vồng" className="gallery-item" />
      <img src="/images/p3.jpg" alt="Bánh chocolate" className="gallery-item" />
      <img src="/images/p4.jpg" alt="Bánh sinh nhật" className="gallery-item" />
    </div>
  </section>
);

export default Gallery;
